INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ペコリーヌとの出会い", "フリーマーケット会場", "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", "青空の下で謁見", 0, 20063115, 7, 1, 40, 91002, 2834, 5118061, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("マホとの出会い", "フリーマーケット会場", "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", "未来の騎空団\nマスコット？", 0, 20063115, 7, 1, 40, 91002, 2835, 5118062, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("アキノとの出会い", "ランドソル市街地", "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", "お嬢さまからの\n緊急依頼", 0, 20063115, 7, 1, 40, 91002, 2837, 5118063, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ジュンとの出会い", "フリーマーケット会場", "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", "黄金色の悩みごと", 0, 20063115, 18, 1, 40, 91002, 4108402, 5118064, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("カオリとの出会い", "フリーマーケット会場", "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", "白熱！　格闘大会！", 0, 20063115, 18, 1, 40, 91002, 4107402, 5118065, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ニノンとの出会い", "オーエド町", "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", "祭り太鼓はオーエドの華", 1, 20063115, 16, 1, 40, 91002, 9000227, 5118066, 10118, 2, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("スズナとの出会い", "フリーマーケット会場", "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", "人気者は遅れて\nやってくる", 0, 20063115, 19, 1, 40, 91002, 2101181, 5118067, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ナナカとの出会い", "ランドソル市街地", "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", "巫女・ミーツ・魔法少女", 0, 20063115, 18, 1, 40, 91002, 4109402, 5118068, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("キャル＆コッコロとの出会い", "フリーマーケット会場", "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", "ネズ耳は二度なくなる", 0, 20063115, 18, 1, 40, 91002, 4305402, 5118069, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("ユカリとの出会い", "ランドソル市街地", "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", "この出会いにカンパイ！", 0, 20063115, 18, 1, 40, 91002, 4101402, 5118070, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("アオイとの出会い", "ランドソル市街地", "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", "陰陽アンサンブル", 0, 20063115, 18, 1, 40, 91002, 4106402, 5118071, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("シノブとの出会い", "フリーマーケット会場", "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", "運試し十番勝負！", 1, 20063115, 7, 1, 40, 91002, 2836, 5118072, 10118, 3, 8);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES ("オープニング", 0, 0, "彼女たちの新たな日常", 0, 20063115, 0, 0, 0, 0, 0, 5118600, 10118, 1, 0);
